function localizedUrl(url){const lang=getActiveLang();const target=new URL(url, window.location.href);target.searchParams.set("lang",lang);return `${target.pathname.split("/").pop()}${target.search}${target.hash}`}
function searchText(value){return normalizeText(value||"")}
function searchLabels(){const lang=getActiveLang();return {de:{hint:"Suchbegriff eingeben.",empty:"Keine Ergebnisse gefunden.",section:"Bereich"},es:{hint:"Escriba una palabra para buscar.",empty:"No se encontraron resultados.",section:"Área"},en:{hint:"Enter a search term.",empty:"No results found.",section:"Area"}}[lang]}
function renderSearchResults(root,query){const results=root.querySelector(".search-results");if(!results)return;const labels=searchLabels();const q=searchText(query);if(q.length<2){results.innerHTML=`<p>${labels.hint}</p>`;return}const lang=getActiveLang();const words=q.split(/\s+/).filter(Boolean);const found=(SITE_SEARCH_INDEX[lang]||SITE_SEARCH_INDEX.de).map(item=>{const hay=searchText(`${item.title} ${item.text}`);const score=words.reduce((sum,word)=>sum+(hay.includes(word)?1:0),0);return {...item,score}}).filter(item=>item.score>0).sort((a,b)=>b.score-a.score).slice(0,8);if(!found.length){results.innerHTML=`<p>${labels.empty}</p>`;return}results.innerHTML=found.map(item=>`<a class="search-result" role="option" href="${localizedUrl(item.url)}"><strong>${item.title}</strong><span>${labels.section}: ${item.text.split(" ").slice(0,8).join(" ")}...</span></a>`).join("")}
function setupSiteSearch(){document.querySelectorAll(".site-search").forEach(root=>{const toggle=root.querySelector(".search-toggle");const panel=root.querySelector(".search-panel");const input=root.querySelector(".site-search-input");const form=root.querySelector(".site-search-form");if(!toggle||!panel||!input||!form)return;toggle.addEventListener("click",()=>{const open=panel.hasAttribute("hidden");document.querySelectorAll(".search-panel").forEach(p=>p.setAttribute("hidden", ""));document.querySelectorAll(".search-toggle").forEach(b=>b.setAttribute("aria-expanded","false"));if(open){panel.removeAttribute("hidden");toggle.setAttribute("aria-expanded","true");input.focus();renderSearchResults(root,input.value)}});input.addEventListener("input",()=>renderSearchResults(root,input.value));form.addEventListener("submit",e=>{e.preventDefault();const first=root.querySelector(".search-result");if(first)first.click();else renderSearchResults(root,input.value)});document.addEventListener("click",e=>{if(!root.contains(e.target)){panel.setAttribute("hidden","");toggle.setAttribute("aria-expanded","false")}})})}
setupSiteSearch();
