function normalizeText(text){return text.toLowerCase().normalize("NFD").replace(/[\u0300-\u036f]/g,"")}
function detectChatLanguage(text){const q=normalizeText(text);let scores={de:0,es:0,en:0};if(/\b(que|como|cual|cuales|servicios|formaciones|empresa|fundadora|contactar|privacidad|hola|gracias|espanol|espana|vision|realidad|modulos|ofrecen)\b/.test(q))scores.es+=3;if(/[¿¡ñáéíóú]/i.test(text))scores.es+=4;if(/\b(was|wie|welche|leistungen|weiterbildungen|unternehmen|grunderin|kontakt|datenschutz|hallo|danke|deutsch|realitat|fur|bietet|gibt)\b/.test(q))scores.de+=3;if(/[äöüß]/i.test(text))scores.de+=4;if(/\b(what|how|which|services|training|company|founder|contact|privacy|hello|thanks|english|future|about|available|offer)\b/.test(q))scores.en+=3;let best=Object.entries(scores).sort((a,b)=>b[1]-a[1])[0];return best[1]>0?best[0]:chatState.lastLanguage||document.documentElement.lang}
function detectChatTopic(text,forcedTopic){if(forcedTopic)return forcedTopic;const q=normalizeText(text);if(/hallo|hello|hola|guten tag|buenos|hi\b/.test(q))return"greeting";if(/modul|formation|weiterbildung|training|curso|prompt|ki lernen|ai learn|formaciones|module/.test(q))return"training";if(/leistung|service|servicio|angebot|consult|beratung|coaching|digitalisierung|digitalizacion|ofrece|offer/.test(q))return"services";if(/grunder|fundador|fundadora|founder|sprachmitt|dominikan|dominican|quien fundo/.test(q))return"founder";if(/azav|zertifiz|certific|forderung|forder|financiacion|subvencion/.test(q))return"azav";if(/vision|heute|realitat|realidad|monolith|future|futuro|monolito/.test(q))return"vision";if(/datenschutz|dsgvo|privacy|privacidad|https|ssl|datos/.test(q))return"privacy";if(/kontakt|contact|whatsapp|email|correo|erstgesprach|consulta|llamar|agendar|cita/.test(q))return"contact";if(/gss|unternehmen|empresa|company|uber uns|about|institucion/.test(q))return"company";return chatState.lastTopic||"fallback"}
function getLocalReply(text,forcedTopic){const lang=detectChatLanguage(text);const topic=detectChatTopic(text,forcedTopic);const knowledge=localKnowledge[lang]||localKnowledge.de;const answers=knowledge[topic]||knowledge.fallback;const list=Array.isArray(answers)?answers:[answers];const index=(chatState.turns+(chatState.askedTopics.filter(t=>t===topic).length))%list.length;chatState.lastTopic=topic;chatState.lastLanguage=lang;chatState.turns+=1;chatState.askedTopics.push(topic);return list[index]}
async function askAI(text,forcedTopic){addChatMessage(text,"user");const detectedLang=detectChatLanguage(text);const detectedTopic=detectChatTopic(text,forcedTopic);if(!AI_CHAT_ENDPOINT){setTimeout(()=>addChatMessage(getLocalReply(text,forcedTopic),"bot"),180);return}try{const response=await fetch(AI_CHAT_ENDPOINT,{method:"POST",headers:{"Content-Type":"application/json"},body:JSON.stringify({message:text,language:detectedLang,topic:detectedTopic,history:chatState.askedTopics.slice(-6)})});const data=await response.json();addChatMessage(data.reply||data.message||getLocalReply(text,forcedTopic),"bot")}catch{addChatMessage(getLocalReply(text,forcedTopic),"bot")}}document.querySelectorAll(".quick").forEach(button=>button.onclick=()=>askAI(button.textContent,button.dataset.topic));if(aiForm&&aiInput){aiForm.onsubmit=e=>{e.preventDefault();const text=aiInput.value.trim();if(text){askAI(text);aiInput.value=""}}}
function contactStatusText(type){const lang=document.documentElement.lang;const texts={ready:{es:"Gracias. Sus datos quedaron preparados para el CRM.",en:"Thank you. Your data is ready for the CRM.",de:"Vielen Dank. Ihre Daten sind für das CRM vorbereitet."},pending:{es:"CRM pendiente de conexión. Los datos quedaron preparados localmente.",en:"CRM connection pending. The data is prepared locally.",de:"CRM-Anbindung noch offen. Die Daten wurden lokal vorbereitet."},whatsappPending:{es:"WhatsApp pendiente de configuración. El lead quedó preparado para el CRM.",en:"WhatsApp is not configured yet. The lead is prepared for the CRM.",de:"WhatsApp ist noch nicht konfiguriert. Der Lead ist für das CRM vorbereitet."},error:{es:"No se pudo enviar al CRM todavía. Revise la configuración del endpoint.",en:"The CRM could not be reached yet. Please check the endpoint configuration.",de:"Das CRM konnte noch nicht erreicht werden. Bitte Endpoint-Konfiguration prüfen."}};return (texts[type]&&texts[type][lang])||texts[type].de}
const PHONE_COUNTRIES={de:{de:"Deutschland",es:"Spanien",us:"USA",at:"Österreich",ch:"Schweiz",fr:"Frankreich",it:"Italien",nl:"Niederlande",be:"Belgien",gb:"Vereinigtes Königreich",do:"Dominikanische Republik"},es:{de:"Alemania",es:"España",us:"Estados Unidos",at:"Austria",ch:"Suiza",fr:"Francia",it:"Italia",nl:"Países Bajos",be:"Bélgica",gb:"Reino Unido",do:"República Dominicana"},en:{de:"Germany",es:"Spain",us:"United States",at:"Austria",ch:"Switzerland",fr:"France",it:"Italy",nl:"Netherlands",be:"Belgium",gb:"United Kingdom",do:"Dominican Republic"}};
