function activeFormLang(){const lang=document.documentElement.lang;return ["de","es","en"].includes(lang)?lang:"de"}
function updatePhoneCountryLabels(){const lang=activeFormLang();document.querySelectorAll('select[name="phoneCountry"] option[data-country]').forEach(option=>{const country=option.dataset.country;const code=option.value.replace(/^\+1(809|829|849)$/,"+1 $1");option.textContent=`${PHONE_FLAGS[country]||""} ${PHONE_COUNTRIES[lang][country]||PHONE_COUNTRIES.de[country]} ${code}`})}
function looksLikeValidEmail(value){const email=(value||"").trim();if(email.length<6||email.length>254)return false;if(email.includes(".."))return false;return /^[^\s@]+@[^\s@]+\.[^\s@]{2,}$/.test(email)}
function looksLikeValidPhone(value,countryCode){const raw=(value||"").replace(/\D/g,"");if(!raw||/(\d)\1{5,}/.test(raw))return false;if(raw.startsWith("00")||raw.startsWith(countryCode.replace("+","")))return false;const rules={"+49":/^(?:0?1[5-7]\d{8,10})$/, "+34":/^[67]\d{8}$/, "+1":/^[2-9]\d{9}$/, "+43":/^(?:0?6\d{7,10})$/, "+41":/^(?:0?7[5-9]\d{7})$/, "+33":/^(?:0?[67]\d{8})$/, "+39":/^3\d{8,9}$/, "+31":/^(?:0?6\d{8})$/, "+32":/^(?:0?4\d{8})$/, "+44":/^(?:0?7\d{9})$/, "+1809":/^[2-9]\d{6}$/, "+1829":/^[2-9]\d{6}$/, "+1849":/^[2-9]\d{6}$/};const rule=rules[countryCode];return rule?rule.test(raw):raw.length>=7&&raw.length<=12}
function setFieldError(input,message){input.setCustomValidity(message);input.reportValidity()}
function validateContactFields(form){const msg=FIELD_MESSAGES[activeFormLang()]||FIELD_MESSAGES.de;const email=form.querySelector('input[name="email"]');const phone=form.querySelector('input[name="phone"]');const phoneCountry=form.querySelector('select[name="phoneCountry"]');const status=form.querySelector(".form-status");if(email&&!looksLikeValidEmail(email.value)){email.setCustomValidity(msg.email);if(status)status.textContent=msg.formError;email.reportValidity();return false}if(phone&&!looksLikeValidPhone(phone.value,phoneCountry?phoneCountry.value:"")){phone.setCustomValidity(msg.phone);if(status)status.textContent=msg.formError;phone.reportValidity();return false}return true}
function validationTextFor(input){const msg=FIELD_MESSAGES[activeFormLang()]||FIELD_MESSAGES.de;if(input.name==="privacyConsent")return msg.privacy;if(input.type==="email"&&input.validity.typeMismatch)return msg.email;if(input.name==="phone"&&input.validity.patternMismatch)return msg.phone;return msg.valueMissing}
function clearCustomValidity(input){input.setCustomValidity("")}
function applyLocalizedValidation(form){if(!form)return;Array.from(form.elements).forEach(input=>{if(!input.willValidate)return;input.oninput=()=>clearCustomValidity(input);input.onchange=()=>clearCustomValidity(input);input.oninvalid=()=>{input.setCustomValidity(validationTextFor(input))}})}
function validateLocalizedForm(form){if(!form)return false;Array.from(form.elements).forEach(clearCustomValidity);if(form.checkValidity())return true;const firstInvalid=Array.from(form.elements).find(input=>input.willValidate&&!input.validity.valid);if(firstInvalid)firstInvalid.setCustomValidity(validationTextFor(firstInvalid));form.reportValidity();return false}
window.updatePhoneCountryLabels=updatePhoneCountryLabels;
window.applyLocalizedValidation=applyLocalizedValidation;
function buildLeadPayload(form,intent){const data=new FormData(form);const topic=data.get("topic");const phoneCountry=data.get("phoneCountry")||"";const phone=(data.get("phone")||"").replace(/\D/g,"");const payload={name:data.get("name")||"",email:data.get("email")||"",phone:phone,phoneCountry:phoneCountry,phoneFull:phone?phoneCountry+phone:"",preferredDate:data.get("preferredDate")||"",requesterType:data.get("requesterType")||"",fundingStatus:data.get("fundingStatus")||"",topic:topic,topicOther:data.get("topicOther")||"",message:data.get("message")||"",privacyConsent:data.get("privacyConsent")==="yes",sourcePage:data.get("sourcePage")||location.pathname,leadSource:data.get("leadSource")||"gss-website",leadIntent:data.get("leadIntent")||"contact",language:document.documentElement.lang,intent:intent||"contact",pageUrl:location.href,createdAt:new Date().toISOString()};if(topic==="other"&&payload.topicOther){payload.topic=payload.topicOther}return payload}
async function sendLeadToCRM(payload){window.gssLastLeadPayload=payload;if(!CRM_LEAD_ENDPOINT){console.info("CRM payload ready",payload);return {ok:false,pending:true}}const response=await fetch(CRM_LEAD_ENDPOINT,{method:"POST",headers:{"Content-Type":"application/json"},body:JSON.stringify(payload)});return {ok:response.ok,pending:false}}
function setupContactForm(){const form=document.querySelector("#contact-form");if(!form)return;const params=new URLSearchParams(location.search);const contactSection=form.closest(".contact");const eyebrow=contactSection&&contactSection.querySelector("[data-i18n=\"contact.eyebrow\"]");const title=contactSection&&contactSection.querySelector("[data-i18n=\"contact.title\"],[data-i18n=\"internal.contact.title\"]");const intro=contactSection&&contactSection.querySelector("[data-i18n=\"contact.text\"],[data-i18n=\"internal.contact.text\"]");const topic=form.querySelector('select[name="topic"]');const other=form.querySelector(".other-topic");const otherInput=form.querySelector('input[name="topicOther"]');const phoneInput=form.querySelector('input[name="phone"]');const phoneCountry=form.querySelector('select[name="phoneCountry"]');const phoneFlag=form.querySelector(".phone-flag");const leadIntent=form.querySelector('input[name="leadIntent"]');const privacy=form.querySelector('input[name="privacyConsent"]');const consultationFields=form.querySelector(".consultation-fields");const consultationToggle=form.querySelector(".consultation-toggle");const requesterType=form.querySelector('select[name="requesterType"]');const status=form.querySelector(".form-status");applyLocalizedValidation(form);function requirePrivacy(){if(!privacy||privacy.checked)return true;privacy.setCustomValidity(validationTextFor(privacy));privacy.reportValidity();return false}function activateConsultation(skipPrivacy){if(!skipPrivacy&&!requirePrivacy())return;if(leadIntent)leadIntent.value="initial-consultation";if(consultationFields)consultationFields.classList.remove("hidden");if(requesterType)requesterType.required=true;if(eyebrow){eyebrow.dataset.i18n="consultation.eyebrow"}if(title){title.dataset.i18n="consultation.title"}if(intro){intro.dataset.i18n="consultation.text"}setLanguage(document.documentElement.lang||"de");if(consultationToggle)consultationToggle.classList.add("hidden")}if(params.get("intent")==="initial-consultation")activateConsultation(true);if(consultationToggle)consultationToggle.onclick=()=>activateConsultation(false);function syncPhoneFlag(){if(!phoneCountry||!phoneFlag)return;const value=phoneCountry.value;const map={"+49":"flag-de","+34":"flag-es","+1":"flag-us","+43":"flag-at","+41":"flag-ch","+33":"flag-fr","+39":"flag-it","+31":"flag-nl","+32":"flag-be","+44":"flag-gb","+1809":"flag-do","+1829":"flag-do","+1849":"flag-do"};phoneFlag.className="phone-flag "+(map[value]||"flag-de")}if(phoneCountry){phoneCountry.addEventListener("change",syncPhoneFlag);syncPhoneFlag()}updatePhoneCountryLabels();if(phoneInput){phoneInput.addEventListener("input",()=>{phoneInput.value=phoneInput.value.replace(/\D/g,"")})}function syncOther(){const show=topic&&topic.value==="other";if(other)other.classList.toggle("hidden",!show);if(otherInput)otherInput.required=!!show;applyLocalizedValidation(form)}if(topic){topic.addEventListener("change",syncOther);syncOther()}async function submit(intent){if(!validateLocalizedForm(form)||!validateContactFields(form))return false;const payload=buildLeadPayload(form,intent);try{const result=await sendLeadToCRM(payload);if(status)status.textContent=result.ok?contactStatusText("ready"):contactStatusText("pending");return true}catch{if(status)status.textContent=contactStatusText("error");return false}}form.onsubmit=async e=>{e.preventDefault();const ok=await submit("contact-form");if(ok)form.reset();syncOther();syncPhoneFlag();updatePhoneCountryLabels()};const whatsappButton=form.querySelector(".whatsapp-contact");if(whatsappButton){whatsappButton.onclick=async()=>{const ok=await submit("whatsapp");if(!ok)return;if(WHATSAPP_URL){window.open(WHATSAPP_URL,"_blank","noopener")}else if(status){status.textContent=contactStatusText("whatsappPending")}}}}
setupContactForm();
const year=document.querySelector("#year");if(year){year.textContent=new Date().getFullYear()}









